			plan:     nil,
			schemas:  &schemarepo.Schemas{},
			expected: "",
		},
		"empty plan": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{},
			},
			schemas:  &schemarepo.Schemas{},
			expected: "",
		},
		"single create": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Create] aws_instance.example\n\n1 resource(s) to change\n",
		},
		"single delete": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Delete,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Delete] aws_instance.example\n\n1 resource(s) to change\n",
		},
		"single update": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Update,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Update] aws_instance.example\n\n1 resource(s) to change\n",
		},
		"multiple creates": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "b"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
							DeposedKey: states.NotDeposed,
						},
						{
							Addr: makeAddr("aws_instance", "a"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Create] aws_instance.a\n[Create] aws_instance.b\n\n2 resource(s) to change\n",
		},
		"mixed actions": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Delete,
							},
							DeposedKey: states.NotDeposed,
						},
						{
							Addr: makeAddr("aws_vpc", "main"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
							DeposedKey: states.NotDeposed,
						},
						{
							Addr: makeAddr("aws_security_group", "web"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Update,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Create] aws_vpc.main\n[Update] aws_security_group.web\n[Delete] aws_instance.example\n\n3 resource(s) to change\n",
		},
		"replace action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.DeleteThenCreate,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[DeleteThenCreate] aws_instance.example\n\n1 resource(s) to change\n",
		},
		"read action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_ami", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Read,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Read] aws_ami.example\n\n1 resource(s) to change\n",
		},
		"with module instance": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.ModuleInstance{
									addrs.ModuleInstanceStep{
										Name: "vpc",
									},
								},
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_subnet",
										Name: "private",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Create] module.vpc.aws_subnet.private\n\n1 resource(s) to change\n",
		},
		"deposed resources are skipped": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Delete,
							},
							DeposedKey: "deposed-key-1",
						},
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Create] aws_instance.example\n\n1 resource(s) to change\n",
		},
		"no-op changes are included": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.NoOp,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "",
		},
		"forget action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Forget,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Forget] aws_instance.example\n\n1 resource(s) to change\n",
		},
	}

	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			formatter := &CompactDiffFormatter{}
			result := formatter.Format(tc.plan, tc.schemas)

			if result != tc.expected {
				t.Errorf("unexpected output\nGot:\n%q\n\nExpected:\n%q", result, tc.expected)
			}
		})
	}
}

func TestCompactDiffFormatter_Sorting(t *testing.T) {
	// Test that resources are sorted alphabetically within each action group
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: makeAddr("aws_instance", "zebra"),
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
					DeposedKey: states.NotDeposed,
				},
				{
					Addr: makeAddr("aws_instance", "apple"),
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
					DeposedKey: states.NotDeposed,
				},
				{
					Addr: makeAddr("aws_vpc", "main"),
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
					DeposedKey: states.NotDeposed,
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, &schemarepo.Schemas{})

	lines := strings.Split(strings.TrimSpace(result), "\n")
	// Should have 3 creates + blank line + summary = 5 lines
	if len(lines) != 5 {
		t.Errorf("expected 5 lines, got %d", len(lines))
	}

	// Check ordering
	if lines[0] != "[Create] aws_instance.apple" {
		t.Errorf("first line should be apple, got %q", lines[0])
	}
	if lines[1] != "[Create] aws_instance.zebra" {
		t.Errorf("second line should be zebra, got %q", lines[1])
	}
	if lines[2] != "[Create] aws_vpc.main" {
		t.Errorf("third line should be vpc.main, got %q", lines[2])
	}
}

// Helper function to create an absolute resource instance address
func makeAddr(resType, name string) addrs.AbsResourceInstance {
	return addrs.AbsResourceInstance{
		Module: addrs.ModuleInstance{},
		Resource: addrs.ResourceInstance{
			Resource: addrs.Resource{
				Mode: addrs.ManagedResourceMode,
				Type: resType,
				Name: name,
			},
		},
	}
}

